    postMessage: vi.fn(),
    onmessage: null,
    onmessageerror: null,
    start: vi.fn(),
    close: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    dispatchEvent: vi.fn(() => true),
  };
}

